const topics = $input.all().map(i => i.json);
const now = new Date();
const fourteenDaysAgo = new Date(now - 14 * 86400000);

const eligible = topics.filter(t => {
  if (!t.last_used_at) return true;
  return new Date(t.last_used_at) < fourteenDaysAgo;
});

if (eligible.length < 3) {
  // Reset: allow all if too few eligible
  eligible.push(...topics.filter(t => !eligible.includes(t)));
}

const totalWeight = eligible.reduce((s, t) => s + parseFloat(t.weight || 1), 0);
const selected = [];
const used = new Set();

while (selected.length < 3 && used.size < eligible.length) {
  let r = Math.random() * totalWeight;
  for (const topic of eligible) {
    if (used.has(topic.id)) continue;
    r -= parseFloat(topic.weight || 1);
    if (r <= 0) {
      selected.push(topic);
      used.add(topic.id);
      break;
    }
  }
}

const ctaVariants = ['direct', 'soft', 'urgency'];
const times = ['09:00', '13:00', '19:00'];

return selected.map((t, i) => ({
  json: {
    ...t,
    post_index: i + 1,
    cta_variant: ctaVariants[i],
    schedule_time: times[i],
    day_number: Math.ceil((now - new Date('2026-03-01')) / 86400000) + 1
  }
}));

const response = $json;
const content = response.content?.[0]?.text || '';
const prev = $input.first().json;

const captionMatch = content.match(/Caption:\s*(.+)/i);
const hashtagMatch = content.match(/Hashtags?:\s*(.+)/i);
const thumbMatch = content.match(/Thumbnail[^:]*:\s*(.+)/i);
const spokenMatch = content.match(/Spoken:\s*(.+)/is);

// Extract spoken text (fallback: strip brackets from script)
let spoken = spokenMatch?.[1]?.trim() || '';
if (!spoken) {
  spoken = content.split('---')[0]
    .replace(/\[.*?\]/g, '')
    .split('\n').map(l => l.trim()).filter(l => l && l.length > 3)
    .join(' ').replace(/\s+/g, ' ');
}

return [{
  json: {
    ...prev,
    script: content,
    caption: (captionMatch?.[1] || '').trim(),
    hashtags: (hashtagMatch?.[1] || '#energy #sleep #focus #productivity #voltsleep').trim(),
    thumbnail_text: (thumbMatch?.[1] || '').trim(),
    spoken_text: spoken,
  }
}];

const post = $json;
const prev = $input.first().json;
const videoUrl = post.url || prev.url || '';
const platforms = ['tiktok', 'instagram', 'youtube', 'facebook'];
const dateStr = new Date().toISOString().split('T')[0];

return platforms.map(platform => {
  const utm = `https://voltsleep.nl?utm_source=${platform}&utm_medium=organic&utm_campaign=daily_${dateStr}&utm_content=hook_${prev.post_index}`;

  let caption = prev.caption;
  if (platform === 'tiktok') caption = `${prev.caption}\n\n${prev.hashtags}\n\nLink in bio`;
  else if (platform === 'instagram') caption = `${prev.caption}\n\n${prev.hashtags}\n\nLink in bio`;
  else if (platform === 'youtube') caption = `${prev.caption} #shorts ${prev.hashtags}`;
  else caption = `${prev.caption}\n\n${prev.hashtags}`;

  return {
    json: {
      platform,
      video_url: videoUrl,
      caption,
      hashtags: prev.hashtags,
      thumbnail_text: prev.thumbnail_text,
      cta_variant: prev.cta_variant,
      day_number: prev.day_number,
      post_index: prev.post_index,
      topic_id: prev.id,
      utm_link: utm,
      scheduled_at: `${dateStr}T${prev.schedule_time}:00Z`,
    }
  };
});
